1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
3	const CURSE_SURCHARGE_RATE = 0.5;
4	const HIGH_ENCHANTMENT_THRESHOLD = 5;
5	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
6	const BLOCK_OF_3_BASE_PREMIUM = 60;
7	const LOYALTY_THRESHOLD_YEARS = 2;
8	const LOYALTY_DISCOUNT_RATE = 0.2;
9	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
10	const DEDUCTIBLE = 100;
11	const CAP_MULTIPLIER = 2;
12	const HIGH_ENCH_CLAIM_THRESHOLD = 8;
13	const HIGH_ENCH_CLAIM_RATE = 0.5;
14	
15	const BASE_PREMIUM: Record<string, number> = {
16	  sword: 100,
17	  amulet: 60,
18	  staff: 80,
19	  potion: 40,
20	  rune: 25,
21	  moonstone: 25,
22	};
23	
24	const INSURANCE_VALUE: Record<string, number> = {
25	  sword: 1000,
26	  amulet: 600,
27	  staff: 800,
28	  potion: 400,
29	  rune: 250,
30	  moonstone: 250,
31	};
32	
33	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
34	
35	type Item = { type: string; material?: string; enchantment?: number; cursed?: boolean };
36	type QuoteStep = { op: "quote"; items: Item[] };
37	type Damage = { itemType: string; amount: number };
38	type Incident = { cause: string; damages: Damage[] };
39	type ClaimStep = { op: "claim"; policy: number; incident: Incident };
40	type Step = QuoteStep | ClaimStep;
41	type Customer = { yearsWithMHPCO: number };
42	type Scenario = { customer: Customer; steps: Step[] };
43	type QuoteResult = { premium: number };
44	type ClaimResult = { payout: number; remainingCap: number };
45	type StepResult = QuoteResult | ClaimResult;
46	
47	type Policy = { items: Item[]; insuranceSum: number; cap: number; capRemaining: number };
48	
49	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
50	
51	const itemSurcharges = (item: Item): number => {
52	  const base = BASE_PREMIUM[item.type];
53	  const curseSurcharge = item.cursed ? base * CURSE_SURCHARGE_RATE : 0;
54	  const highEnchSurcharge =
55	    (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
56	      ? base * HIGH_ENCHANTMENT_SURCHARGE_RATE
57	      : 0;
58	  return curseSurcharge + highEnchSurcharge;
59	};
60	
61	const countByType = (items: Item[]): Map<string, number> => {
62	  const counts = new Map<string, number>();
63	  for (const item of items) {
64	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
65	  }
66	  return counts;
67	};
68	
69	const componentGroupBase = (type: string, count: number): number =>
70	  count === 3 ? BLOCK_OF_3_BASE_PREMIUM : count * BASE_PREMIUM[type];
71	
72	const policyBase = (items: Item[]): number => {
73	  const components = items.filter(isComponent);
74	  const mainItems = items.filter((item) => !isComponent(item));
75	  const mainBase = mainItems.reduce((sum, item) => sum + BASE_PREMIUM[item.type], 0);
76	  const componentBase = Array.from(countByType(components)).reduce(
77	    (sum, [type, count]) => sum + componentGroupBase(type, count),
78	    0,
79	  );
80	  return mainBase + componentBase;
81	};
82	
83	const sumItemSurcharges = (items: Item[]): number =>
84	  items.reduce((sum, item) => sum + itemSurcharges(item), 0);
85	
86	const loyaltyDiscount = (customer: Customer, base: number): number =>
87	  customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS ? base * LOYALTY_DISCOUNT_RATE : 0;
88	
89	const followUpDiscount = (isFollowUp: boolean, base: number): number =>
90	  isFollowUp ? base * FOLLOW_UP_DISCOUNT_RATE : 0;
91	
92	const quoteStep = (step: QuoteStep, customer: Customer, isFollowUp: boolean): QuoteResult => {
93	  const base = policyBase(step.items);
94	  const firstInsurance = base * FIRST_INSURANCE_SURCHARGE_RATE;
95	  const premium =
96	    base +
97	    firstInsurance -
98	    loyaltyDiscount(customer, base) -
99	    followUpDiscount(isFollowUp, base) +
100	    sumItemSurcharges(step.items) +
101	    PROCESSING_FEE;
102	  return { premium: Math.ceil(premium) };
103	};
104	
105	const insuranceSum = (items: Item[]): number =>
106	  items.reduce((sum, item) => sum + INSURANCE_VALUE[item.type], 0);
107	
108	const makePolicy = (items: Item[]): Policy => {
109	  const sum = insuranceSum(items);
110	  const cap = sum * CAP_MULTIPLIER;
111	  return { items, insuranceSum: sum, cap, capRemaining: cap };
112	};
113	
114	const damagePayout = (damage: Damage, policy: Policy): number => {
115	  const item = policy.items.find((i) => i.type === damage.itemType);
116	  const reduced = (item?.enchantment ?? 0) >= HIGH_ENCH_CLAIM_THRESHOLD
117	    ? damage.amount * HIGH_ENCH_CLAIM_RATE
118	    : damage.amount;
119	  return reduced - DEDUCTIBLE;
120	};
121	
122	const totalPayout = (damages: Damage[], policy: Policy): number =>
123	  damages.reduce((sum, d) => sum + damagePayout(d, policy), 0);
124	
125	const claimStep = (step: ClaimStep, policies: Policy[]): ClaimResult => {
126	  const policy = policies[step.policy];
127	  const payout = totalPayout(step.incident.damages, policy);
128	  policy.capRemaining -= payout;
129	  return { payout, remainingCap: policy.capRemaining };
130	};
131	
132	export const runScenario = (scenario: Scenario): { results: StepResult[] } => {
133	  const policies: Policy[] = [];
134	  const results: StepResult[] = scenario.steps.map((step) => {
135	    if (step.op === "quote") {
136	      const isFollowUp = policies.length > 0;
137	      policies.push(makePolicy(step.items));
138	      return quoteStep(step, scenario.customer, isFollowUp);
139	    }
140	    return claimStep(step, policies);
141	  });
142	  return { results };
143	};
